1	// Utility type: union of all possible tool_name/data pairs
2	type ToolDataUnion = {
3	  [K in ToolName]: { tool_name: K; data: ToolDataMap[K] };
4	}[ToolName];
5	
6	function getTypedData<K extends ToolName>(
7	  entry: ToolDataUnion,
8	  toolName: K,
9	): ToolDataMap[K] | undefined {
10	  return entry.tool_name === toolName
11	    ? (entry.data as ToolDataMap[K])
12	    : undefined;
13	}
