522	function renderTool<K extends ToolName>(
523	  name: K,
524	  data: ToolDataMap[K],
525	  index: number,
526	): React.ReactNode {
527	  const renderer = TOOL_RENDERERS[name] as
528	    | ((data: ToolDataMap[K], index: number) => React.ReactNode)
529	    | undefined;
530	  return renderer ? renderer(data, index) : null;
531	}
