533	export default function TextBubble({
534	  text,
535	  disclaimer,
536	  tool_data,
537	  isConvoSystemGenerated,
538	  systemPurpose,
539	  loading,
540	}: ChatBubbleBotProps) {
541	  const baseId = useId();
542	
543	  // Parse thinking content from text
544	  const parsedContent = React.useMemo(() => {
545	    return parseThinkingFromText(text?.toString() || "");
546	  }, [text]);
547	
548	  const processedTools = React.useMemo(() => {
549	    const grouped = new Map<ToolName, ToolDataMap[ToolName][]>();
550	    const individual: ToolDataEntry[] = [];
551	
552	    tool_data?.forEach((entry) => {
553	      const toolName = entry.tool_name as ToolName;
554	      if (GROUPED_TOOLS.has(toolName)) {
555	        if (!grouped.has(toolName)) grouped.set(toolName, []);
556	        grouped.get(toolName)!.push(entry.data);
557	      } else {
558	        individual.push(entry);
559	      }
560	    });
561	
562	    const groupedEntries: ToolDataEntry[] = Array.from(grouped.entries()).map(
563	      ([toolName, dataArray]) => ({
564	        tool_name: toolName,
565	        tool_category: "",
566	        data: dataArray as ToolDataMap[ToolName],
567	        timestamp: null,
568	      }),
569	    );
570	
571	    return [...groupedEntries, ...individual];
572	  }, [tool_data]);
573	
574	  return (
575	    <>
576	      {parsedContent.thinking && (
577	        <ThinkingBubble thinkingContent={parsedContent.thinking} />
578	      )}
579	
580	      {processedTools.map((entry, index) => {
581	        const toolName = entry.tool_name as ToolName;
582	        const keyId = entry.timestamp || index;
583	
584	        if (toolName === "todo_progress") {
585	          const data = getTypedData(entry as ToolDataUnion, "todo_progress");
586	          return data ? (
587	            <React.Fragment key={`${baseId}-tool-${toolName}-${keyId}`}>
588	              <TodoProgressSection
589	                todo_progress={data as TodoProgressData}
590	                isStreaming={loading}
591	              />
592	            </React.Fragment>
593	          ) : null;
594	        }
595	
596	        const renderer = TOOL_RENDERERS[toolName];
597	        if (!renderer) return null;
598	
599	        const typedData = getTypedData(entry as ToolDataUnion, toolName);
600	        if (!typedData) return null;
601	
602	        const toolCallId =
603	          typeof typedData === "object" &&
604	          typedData !== null &&
605	          "tool_call_id" in typedData
606	            ? String(
607	                (typedData as unknown as { tool_call_id?: string })
608	                  .tool_call_id ?? "",
609	              )
610	            : "";
611	        const toolKey = toolCallId
612	          ? `${baseId}-tool-${toolName}-${toolCallId}`
613	          : `${baseId}-tool-${toolName}-${index}`;
614	
615	        return (
616	          <React.Fragment key={toolKey}>
617	            {renderTool(toolName, typedData, index)}
618	          </React.Fragment>
619	        );
620	      })}
621	
622	      {shouldShowTextBubble(text, isConvoSystemGenerated, systemPurpose) &&
623	        (() => {
624	          const displayText = parsedContent.cleanText || "";
625	          const textParts = displayText.includes(":::openui")
626	            ? splitByBreaksPreservingFences(displayText)
627	            : splitMessageByBreaks(displayText);
628	
629	          return (
630	            <div className="flex flex-col">
631	              {textParts.map((part, index) => {
632	                const isFirst = index === 0;
633	                const isLast = index === textParts.length - 1;
634	                const isSingle = textParts.length === 1;
635	                const segments = parseOpenUISegments(part, !!loading);
636	                const hasOpenUI = segments.some((s) => s.type === "openui");
637	
638	                // ── Pure markdown part — normal iMessage bubble ──────────────
639	                if (!hasOpenUI) {
640	                  const isEmojiOnly = isOnlyEmojis(part);
641	                  const emojiCount = isEmojiOnly ? getEmojiCount(part) : 0;
642	
643	                  let groupedClasses = isSingle
644	                    ? "imessage-grouped-last"
645	                    : isFirst
646	                      ? "imessage-grouped-first mb-1.5"
647	                      : isLast
648	                        ? "imessage-grouped-last"
649	                        : "imessage-grouped-middle mb-1.5";
650	
651	                  let bubbleClassName = "imessage-bubble imessage-from-them";
652	                  let textClass = "";
653	
654	                  if (isEmojiOnly) {
655	                    if (emojiCount === 1) {
656	                      bubbleClassName = "select-none";
657	                      groupedClasses = "";
658	                      textClass = "text-[4rem] leading-none";
659	                    } else if (emojiCount === 2) {
660	                      textClass = "text-5xl";
661	                    } else if (emojiCount === 3) {
662	                      textClass = "text-4xl";
663	                    }
664	                  }
665	
666	                  return (
667	                    <m.div
668	                      // biome-ignore lint/suspicious/noArrayIndexKey: array is stable
669	                      key={`${baseId}-text-part-${index}`}
670	                      className={`${bubbleClassName} ${groupedClasses}`}
671	                      initial={{ opacity: 0, y: 6 }}
672	                      animate={{ opacity: 1, y: 0 }}
673	                      transition={{
674	                        duration: 0.3,
675	                        ease: MESSAGE_BREAK_EASE_OUT_QUART,
676	                        delay: index * MESSAGE_BREAK_STAGGER_SECONDS,
677	                      }}
678	                    >
679	                      <div className={textClass}>
680	                        <div className="flex flex-col gap-3">
681	                          <MarkdownRenderer
682	                            content={part}
683	                            isStreaming={loading}
684	                          />
685	                          {!!disclaimer && isLast && (
686	                            <Chip
687	                              className="text-xs font-medium text-warning-500"
688	                              color="warning"
689	                              size="sm"
690	                              startContent={
691	                                <Alert01Icon
692	                                  className="text-warning-500"
693	                                  height={17}
694	                                />
695	                              }
696	                              variant="flat"
697	                            >
698	                              {disclaimer}
699	                            </Chip>
700	                          )}
701	                        </div>
702	                      </div>
703	                    </m.div>
704	                  );
705	                }
706	
707	                // ── Mixed part: openui segments render OUTSIDE the bubble ────
708	                // OpenUI components use bg-zinc-800 which would be invisible
709	                // inside the imessage-from-them bubble (same background color).
710	                // Markdown segments get their own compact bubbles; openui
711	                // segments are rendered at the same level as tool cards.
712	                const lastMdIdx = segments.reduce(
713	                  (acc, s, i) =>
714	                    s.type === "markdown" && s.content.trim() ? i : acc,
715	                  -1,
716	                );
717	
718	                return (
719	                  <m.div
720	                    // biome-ignore lint/suspicious/noArrayIndexKey: array is stable
721	                    key={`${baseId}-text-part-${index}`}
722	                    className="flex flex-col"
723	                    initial={{ opacity: 0, y: 6 }}
724	                    animate={{ opacity: 1, y: 0 }}
