738	                            isStreaming={!!loading && !seg.isComplete}
739	                          />
740	                        );
741	                      }
742	                      if (!seg.content.trim()) return null;
743	                      const isLastMdInLastPart = isLast && segIdx === lastMdIdx;
744	                      return (
745	                        <div
746	                          key={segKey}
747	                          className={`imessage-bubble imessage-from-them ${isLastMdInLastPart ? "imessage-grouped-last" : "imessage-grouped-first"} mb-1.5`}
748	                        >
