"use client";

import type { ReactNode } from "react";
import { useEffect, useMemo, useRef, useState } from "react";
import BlurStack, { type BlurLayer } from "@/components/ui/blur-stack";
import { getProgress, PROGRESS_TOTAL_STEPS } from "../state/derive";
import type { OnboardingState, Stage } from "../state/types";
import { OnboardingProgress } from "./OnboardingProgress";

// Heavy-blur-at-top config — mirror of the default heavy-at-bottom stack.
const TOP_BLUR_CONFIG: BlurLayer[] = [
  { blur: 0.5, maskStops: [62.5, 75, 87.5, 100], zIndex: 1 },
  { blur: 1, maskStops: [50, 62.5, 75, 87.5], zIndex: 2 },
  { blur: 2, maskStops: [37.5, 50, 62.5, 75], zIndex: 3 },
  { blur: 4, maskStops: [25, 37.5, 50, 62.5], zIndex: 4 },
  { blur: 8, maskStops: [12.5, 25, 37.5, 50], zIndex: 5 },
  { blur: 16, maskStops: [0, 12.5, 25, 37.5], zIndex: 6 },
  { blur: 32, maskStops: [0, 0, 12.5, 25], zIndex: 7 },
  { blur: 64, maskStops: [0, 0, 0, 12.5], zIndex: 8 },
];

interface OnboardingShellProps {
  state: OnboardingState;
  stage: Stage;
  onRestart: () => void;
  children: ReactNode;
  composer?: ReactNode;
}

/**
 * Single string fingerprint of "what's on screen". Used as a useEffect dep so
 * scroll-to-bottom fires once per content change instead of needing 7 deps.
 */
function getContentFingerprint(state: OnboardingState, stage: Stage): string {
  const b = state.server;
  // Concat every active progress slot — any change to any stage's status_text
  // should re-trigger the scroll-to-bottom effect.
  const progress = Object.values(state.progressByStage).join("");
  return [
    stage,
    state.questionIndex,
    progress,
    state.completedStages.size,
    state.ackedWritingStyle ? 1 : 0,
    state.ackedTodos ? 1 : 0,
    state.workflowsConfirmed ? 1 : 0,
    state.platformsConfirmed ? 1 : 0,
    state.connectedPlatform ?? "",
    b?.writing_style?.style_summary ?? "",
    b?.onboarding_todos?.length ?? 0,
    b?.suggested_workflows?.length ?? 0,
    b?.first_message_conversation_id ?? "",
    state.todoExecutionMessage ?? "",
    // Each clarify answer adds a bot+user bubble pair to the transcript —
    // include the count so scroll-to-bottom fires as the user answers.
    Object.keys(state.clarifyAnswers).length,
    state.clarifySubmitted ? 1 : 0,
  ].join("|");
}

// Extra breathing room below the chat content so the composer never sits
// flush against the last bubble. Tuned to match the visual rhythm of the
// blur stack at the bottom of the shell.
const COMPOSER_GUTTER_PX = 24;
// Bottom blur stack is `h-24` (Tailwind 6rem = 96px). When there's no docked
// composer, content must still clear this overlay so it isn't smudged behind
// the blur — e.g. the processing checklist on the no-Gmail path.
const BOTTOM_BLUR_PX = 96;

export function OnboardingShell({
  state,
  stage,
  onRestart,
  children,
  composer,
}: OnboardingShellProps) {
  const scrollRef = useRef<HTMLDivElement>(null);
  const composerRef = useRef<HTMLDivElement>(null);
  const [composerHeight, setComposerHeight] = useState(0);
  const progressStep = getProgress(state, stage);
  const fingerprint = useMemo(
    () => getContentFingerprint(state, stage),
    [state, stage],
  );

  // Track composer height so the scroll container always has enough bottom
  // padding for the docked composer — short text inputs and tall multi-step
  // forms (like clarify) both get the right gutter without hardcoded values.
  // Re-attach the observer whenever the composer mounts/unmounts so a stage
  // change always picks up the new DOM node.
  const hasComposer = !!composer;
  useEffect(() => {
    const el = composerRef.current;
    if (!el) {
      setComposerHeight(0);
      return;
    }
    const update = () => setComposerHeight(el.getBoundingClientRect().height);
    update();
    const obs = new ResizeObserver(update);
    obs.observe(el);
    return () => obs.disconnect();
  }, [hasComposer, stage]);

  useEffect(() => {
    scrollRef.current?.scrollTo({
      top: scrollRef.current.scrollHeight,
      behavior: "smooth",
    });
    // Also re-pin when the composer grows (e.g. the "Other" input expands in
    // the clarify composer) — without this, the last bubble can fall behind
    // a newly-taller composer.
  }, [fingerprint, composerHeight]);

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-primary-bg backdrop-blur-2xl">
      <div
        aria-hidden
        className="pointer-events-none absolute inset-0 z-0 bg-center bg-cover opacity-40"
        style={{
          backgroundImage: "url('/images/wallpapers/bands_gradient_black.png')",
        }}
      />
      <OnboardingProgress
        currentStep={progressStep}
        totalSteps={PROGRESS_TOTAL_STEPS}
        onRestart={onRestart}
        isRestarting={state.isRestarting}
      />

      <div
        ref={scrollRef}
        className="relative z-10 flex-1 overflow-y-auto px-4 pt-20"
      >
        <div
          className="relative mx-auto w-full max-w-3xl"
          style={{
            paddingBottom:
              Math.max(composer ? composerHeight : 0, BOTTOM_BLUR_PX) +
              COMPOSER_GUTTER_PX,
          }}
        >
          {children}
        </div>
      </div>

      <BlurStack
        className="pointer-events-none fixed top-0 right-0 left-0 z-20 h-24"
        config={TOP_BLUR_CONFIG}
      />
      <BlurStack className="pointer-events-none fixed right-0 bottom-0 left-0 z-20 h-24" />

      {composer && (
        <div
          ref={composerRef}
          className={
            // Clarify composer is a multi-question card — give it more room
            // than the standard text composer. Every other stage stays at
            // max-w-lg so the visual rhythm of the existing flow is unchanged.
            stage === "clarify"
              ? "fixed inset-x-0 bottom-0 z-30 mx-auto w-full max-w-xl pb-3"
              : "fixed inset-x-0 bottom-0 z-30 mx-auto w-full max-w-lg pb-3"
          }
        >
          {composer}
        </div>
      )}
    </div>
  );
}

