1	/**
2	 * `clarify` stage. Non-Gmail users answer 3 follow-up questions
3	 * (scope / blocker / constraint) so the todo generator has enough signal
4	 * to produce concrete actions. UI lives entirely in the composer footer:
5	 * HeroUI Tabs for navigation, RadioGroup for options, an "Other" radio
6	 * that reveals an Input, and a "Skip this question" radio. Submit unlocks
7	 * once every question has either an option, a committed custom answer,
8	 * or a skip.
9	 */
10	
11	"use client";
12	
13	import { Button } from "@heroui/button";
14	import { Input } from "@heroui/input";
15	import { Radio, RadioGroup } from "@heroui/radio";
16	import { Skeleton } from "@heroui/skeleton";
17	import { Tab, Tabs } from "@heroui/tabs";
18	import { CheckmarkCircle02Icon, CircleArrowRight02Icon } from "@icons";
19	import { AnimatePresence } from "motion/react";
20	import * as m from "motion/react-m";
21	import type { Dispatch } from "react";
22	import { useCallback, useMemo } from "react";
23	import {
24	  CLARIFY_OTHER_LABEL,
25	  CLARIFY_SKIP_LABEL,
26	} from "../../constants/clarify";
27	import { EASE_OUT_QUART } from "../../constants/motion";
28	import type { Action, OnboardingState } from "../../state/types";
29	import {
30	  CLARIFY_RADIO_BASE_CLASS,
31	  CLARIFY_RADIO_LABEL_CLASS,
32	  CLARIFY_RADIO_LABEL_MUTED_CLASS,
33	  countAnsweredClarify,
34	  isQuestionAnswered,
35	  OPTION_VALUE_PREFIX,
36	  OTHER_VALUE,
37	  radioValueFor,
38	  SKIP_VALUE,
39	} from "../../utils/clarifyHelpers";
40	
41	interface ClarifyProps {
42	  state: OnboardingState;
43	  dispatch: Dispatch<Action>;
44	}
45	
46	export function ClarifyComposer({ state, dispatch }: ClarifyProps) {
47	  const questions = state.clarifyQuestions ?? [];
48	  const activeId = state.clarifyActiveTab ?? questions[0]?.id ?? "";
49	  const activeQuestion = useMemo(
50	    () => questions.find((q) => q.id === activeId) ?? questions[0],
51	    [questions, activeId],
52	  );
53	
54	  const answeredCount = countAnsweredClarify(state);
55	  const allAnswered =
