15	 * pipeline hasn't started yet. Idempotent via an in-flight ref *and* the
16	 * persisted `user.onboarding.completed` flag — the in-flight ref alone is
17	 * insufficient because any remount (OAuth bounce, back-nav from /c/{id},
18	 * manual refresh) creates a fresh ref while `state.server` is still null
19	 * until `useBackendSync`'s async snapshot fetch resolves. Without the
20	 * persisted guard, the user-store flag wins that race and a duplicate POST
21	 * fires, re-running the intelligence pipeline.
22	 *
23	 * The snapshot-based guard only bails when the snapshot reports a phase past
24	 * `"initial"`. A bare `state.server != null` check would trap the no-Gmail
25	 * path: `useBackendSync` activates at `"clarify"` and resolves the initial
26	 * snapshot before the user finishes answering, so by submit time `server`
27	 * is non-null but the pipeline has not started yet. The phase check matches
28	 * the original intent ("pipeline already running") without the false bail.
29	 */
30	export function useOnboardingSubmission(
31	  state: OnboardingState,
32	  onSuccess?: (user: UserInfo) => void,
33	): void {
34	  const inFlightRef = useRef(false);
35	  const alreadyCompleted = useUserStore(
36	    (s) => s.onboarding?.completed === true,
37	  );
38	
39	  useEffect(() => {
40	    if (inFlightRef.current) return;
41	    if (state.isRestarting) return;
42	    const serverPhase = state.server?.phase;
43	    if (serverPhase && serverPhase !== "initial") return;
44	    if (alreadyCompleted) return;
45	    if (!isResponsesComplete(state)) return;
46	
47	    inFlightRef.current = true;
48	    const responses = state.responses;
49	    // Clarify follow-up answers only exist on the no-Gmail path. Skipped
50	    // answers are dropped server-side so we don't pre-filter here — the
51	    // backend keeps things explicit by storing only non-null values.

